+/**
+ * Lighting system with radial gradient torch glow and flicker animation.
+ * Torches emit warm light, room corners darker.
+ * Flicker animation simulates embers.
+ */
+
+class Lighting {
+  constructor(canvas, context, roomWidth, roomHeight, torches) {
+    this.canvas = canvas;
+    this.ctx = context;
+    this.roomWidth = roomWidth;
+    this.roomHeight = roomHeight;
+    this.torches = torches; // Array of {x, y} torch positions
+    this.animationFrame = 0;
+    this.flickerIntensity = 0;
+    this.flickerDirection = 1;
+  }
+
+  update() {
+    // Update flicker intensity for embers flicker effect
+    this.flickerIntensity += this.flickerDirection * 0.02;
+    if (this.flickerIntensity > 1 || this.flickerIntensity < 0.6) {
+      this.flickerDirection *= -1;
+    }
+    this.animationFrame++;
+  }
+
+  draw() {
+    const ctx = this.ctx;
+    const w = this.roomWidth;
+    const h = this.roomHeight;
+
+    // Clear canvas
+    ctx.clearRect(0, 0, w, h);
+
+    // Draw dark overlay for room corners - radial gradient from center to corners
+    const cornerGradient = ctx.createRadialGradient(w/2, h/2, w/4, w/2, h/2, w);
+    cornerGradient.addColorStop(0, 'rgba(0,0,0,0)');
+    cornerGradient.addColorStop(1, 'rgba(0,0,0,0.7)');
+    ctx.fillStyle = cornerGradient;
+    ctx.fillRect(0, 0, w, h);
+
+    // Draw torches light
+    this.torches.forEach(torch => {
+      this.drawTorchLight(torch.x, torch.y);
+    });
+  }
+
+  drawTorchLight(x, y) {
+    const ctx = this.ctx;
+    // Flicker radius changes slightly with flicker intensity
+    const baseRadius = 120;
+    const flickerRadius = baseRadius * (0.9 + 0.2 * this.flickerIntensity);
+
+    // Create radial gradient for warm torch light
+    const gradient = ctx.createRadialGradient(x, y, 10, x, y, flickerRadius);
+    gradient.addColorStop(0, 'rgba(255, 180, 100, 0.9)'); // bright warm center
+    gradient.addColorStop(0.4, 'rgba(255, 140, 50, 0.5)');
+    gradient.addColorStop(1, 'rgba(255, 100, 0, 0)'); // fade out
+
+    ctx.fillStyle = gradient;
+    ctx.beginPath();
+    ctx.arc(x, y, flickerRadius, 0, Math.PI * 2);
+    ctx.fill();
+
+    // Draw subtle ember flicker (small glowing particles)
+    this.drawEmbers(x, y, flickerRadius);
+  }
+
+  drawEmbers(x, y, radius) {
+    const ctx = this.ctx;
+    const emberCount = 6;
+    for (let i = 0; i < emberCount; i++) {
+      // Position embers randomly around torch center with flicker offset
+      const angle = (Math.PI * 2 / emberCount) * i + (this.animationFrame * 0.1);
+      const distance = radius * (0.5 + 0.3 * Math.sin(this.animationFrame * 0.05 + i));
+      const emberX = x + Math.cos(angle) * distance;
+      const emberY = y + Math.sin(angle) * distance * 0.6; // slight vertical ellipse
+
+      // Ember flicker alpha oscillates
+      const alpha = 0.3 + 0.4 * Math.sin(this.animationFrame * 0.2 + i);
+
+      const emberGradient = ctx.createRadialGradient(emberX, emberY, 1, emberX, emberY, 5);
+      emberGradient.addColorStop(0, `rgba(255, 180, 80, ${alpha.toFixed(2)})`);
+      emberGradient.addColorStop(1, 'rgba(255, 180, 80, 0)');
+
+      ctx.fillStyle = emberGradient;
+      ctx.beginPath();
+      ctx.arc(emberX, emberY, 5, 0, Math.PI * 2);
+      ctx.fill();
+    }
+  }
+}
+
+export default Lighting;
